patch:
diff --git a/llvm/lib/Transforms/Utils/SCCPSolver.cpp b/llvm/lib/Transforms/Utils/SCCPSolver.cpp
index 4225e7e80fda..9fff388f4bfc 100644
--- a/llvm/lib/Transforms/Utils/SCCPSolver.cpp
+++ b/llvm/lib/Transforms/Utils/SCCPSolver.cpp
@@ -55,6 +55,35 @@ bool SCCPSolver::isOverdefined(const ValueLatticeElement &LV) {
 }

 bool SCCPSolver::tryToReplaceWithConstant(Value *V) {
+  // Avoid replacing FCmp with constants under dynamic denormal mode.
+  if (auto *I = dyn_cast<Instruction>(V)) {
+    if (I->getOpcode() == Instruction::FCmp) {
+      const Function *F = I->getFunction();
+      if (F) {
+        DenormalMode Mode = F->getDenormalMode(APFloat::IEEEdouble());
+        if (Mode.Input == DenormalMode::Dynamic || Mode.Output == DenormalMode::Dynamic) {
+          auto HasDenorm = [](Value *Op) {
+            if (auto *CFP = dyn_cast<ConstantFP>(Op)) return CFP->getValueAPF().isDenormal();
+            if (auto *CV = dyn_cast<Constant>(Op)) {
+              Type *Ty = CV->getType();
+              if (Ty->isVectorTy() && Ty->getScalarType()->isFloatingPointTy()) {
+                auto *FVT = dyn_cast<FixedVectorType>(Ty);
+                unsigned N = FVT ? FVT->getNumElements() : 0;
+                for (unsigned i = 0; i < N; ++i) {
+                  if (auto *Elt = CV->getAggregateElement(i))
+                    if (auto *EltFP = dyn_cast<ConstantFP>(Elt))
+                      if (EltFP->getValueAPF().isDenormal()) return true;
+                }
+              }
+            }
+            return false;
+          };
+          if (HasDenorm(I->getOperand(0)) || HasDenorm(I->getOperand(1)))
+            return false;
+        }
+      }
+    }
+  }
   Constant *Const = getConstantOrNull(V);
   if (!Const)
     return false;

